class Solution:
    def minimumAddedCoins(self, coins: List[int], target: int) -> int:
        coins.sort()
        current_max = 0
        added_coins = 0
        i = 0

        while current_max < target:
            if i < len(coins) and coins[i] <= current_max + 1:
                current_max += coins[i]
                i += 1
            else:
                added_coins += 1
                current_max += current_max + 1

        return added_coins
